{
  "kind": "singleType",
  "collectionName": "site_settings",
  "info": {
    "singularName": "site-setting",
    "pluralName": "site-settings",
    "displayName": "Site Settings"
  },
  "options": {
    "draftAndPublish": false
  },
  "attributes": {
    "siteName": {
      "type": "string",
      "required": true,
      "default": "My Site"
    },
    "siteDescription": {
      "type": "text",
      "maxLength": 200
    },
    "logo": {
      "type": "media",
      "multiple": false,
      "required": false,
      "allowedTypes": ["images"]
    },
    "favicon": {
      "type": "media",
      "multiple": false,
      "allowedTypes": ["images"]
    },
    "contactEmail": {
      "type": "email",
      "required": true
    },
    "socialLinks": {
      "type": "component",
      "repeatable": true,
      "component": "links.social-link"
    },
    "seo": {
      "type": "component",
      "repeatable": false,
      "component": "shared.seo"
    },
    "maintenanceMode": {
      "type": "boolean",
      "default": false
    },
    "maintenanceMessage": {
      "type": "richtext"
    }
  }
}

// GET request - no ID needed
const response = await fetch(
  'https://api.example.com/api/site-setting?populate=*',
  {
    headers: {
      'Authorization': `Bearer ${API_TOKEN}`
    }
  }
);

const { data } = await response.json();
// data.attributes contains the single type content

// PUT request - no ID in URL
const response = await fetch(
  'https://api.example.com/api/site-setting',
  {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_TOKEN}`
    },
    body: JSON.stringify({
      data: {
        siteName: 'Updated Site Name',
        maintenanceMode: false
      }
    })
  }
);

const { data } = await response.json();
